SELECT DISTINCT pi.policy_id
FROM policy_impact pi
WHERE pi.impact_TYPE = 'Economic';

SELECT policy_id
FROM policy_updates
WHERE update_type = 'Extension';

SELECT COUNT(*) 
FROM policy_reviews 
WHERE re_reviewed = 1;

SELECT metric_VALUE
FROM policy_metrics
WHERE policy_id = 0;

SELECT COUNT(policy_id) AS policy_count
FROM policies
WHERE mandate = 1 AND statewide = 0;
